import React, { useState } from "react";
import "./Calendar.css";
import CalendarGrid from "./CalendarGrid";
import events from "../data/events";

const Calendar = () => {
  const [view, setView] = useState("month");
  const [activeBtn, setActiveBtn] = useState("month");

  const [filters, setFilters] = useState({
    holiday: true,
    leave: true,
    birthday: true,
  });

  const handleFilterChange = (type) => {
    setFilters((prev) => ({
      ...prev,
      [type]: !prev[type],
    }));
  };

  return (
    <div className="calendar-layout">
      {/* LEFT FILTER SIDEBAR */}
      <div className="calendar-filters">
        <h3>Filters</h3>

        <label>
          <input
            type="checkbox"
            checked={filters.holiday}
            onChange={() => handleFilterChange("holiday")}
          />
          Holidays (Green)
        </label>

        <label>
          <input
            type="checkbox"
            checked={filters.leave}
            onChange={() => handleFilterChange("leave")}
          />
          Leaves (Yellow)
        </label>

        <label>
          <input
            type="checkbox"
            checked={filters.birthday}
            onChange={() => handleFilterChange("birthday")}
          />
          Birthdays (Blue)
        </label>
      </div>

      {/* MAIN CALENDAR */}
      <div className="calendar-main">
        <div className="calendar-header">
          <button
            className={`btn ${activeBtn === "month" ? "active" : ""}`}
            onClick={() => {
              setView("month");
              setActiveBtn("month");
            }}
          >
            Month
          </button>

          <div className="nav-buttons">
            <button
              className={`btn ${activeBtn === "prev" ? "active" : ""}`}
              onClick={() => setActiveBtn("prev")}
            >
              Prev
            </button>

            <span className="month-label">December 2025</span>

            <button
              className={`btn ${activeBtn === "next" ? "active" : ""}`}
              onClick={() => setActiveBtn("next")}
            >
              Next
            </button>
          </div>

          <button
            className={`btn ${activeBtn === "week" ? "active" : ""}`}
            onClick={() => {
              setView("week");
              setActiveBtn("week");
            }}
          >
            Week
          </button>
        </div>

        <CalendarGrid
          view={view}
          events={events}
          filters={filters}
        />
      </div>
    </div>
  );
};

export default Calendar;
